WHERE 
ORDER BY p.${sortBy} ${sortDir}
LIMIT #{limit} OFFSET #{offset}



    AND (p.name LIKE CONCAT('%', #{keyword}, '%')
             OR p.description LIKE CONCAT('%', #{keyword}, '%')
             OR p.brand LIKE CONCAT('%', #{keyword}, '%'))


        AND p.category_id = #{categoryId}


        AND p.brand LIKE CONCAT('%', #{brand}, '%')


        AND p.cpu LIKE CONCAT('%', #{cpu}, '%')


        AND p.ram LIKE CONCAT('%', #{ram}, '%')


        AND p.storage LIKE CONCAT('%', #{storage}, '%')


        AND p.price >= #{minPrice}


        AND p.price <= #{maxPrice}

    AND p.deleted = 0

ORDER BY p.${sortBy} ${sortDir}
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM products p
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%') OR p.brand LIKE CONCAT('%', #{keyword}, '%'))
